<script setup lang="ts">
const props = defineProps({
  modelValue: {
    type: [Boolean, Object as () => any],
    default: false
  },
  id: {
    type: String,
    required: true
  },
  value: {
    type: String,
    required: true
  },
  name: {
    type: String,
    default: ''
  },
  label: {
    type: String,
    default: ''
  },
  color: {
    type: String as () => 'default' | 'primary' | 'success' | 'info' | 'warning' |'error',
    default: 'default'
  }
})

const emit = defineEmits(['update:model-value'])

const variant = {
  default: 'text-gray-500',
  primary: 'text-primary-500',
  success: 'text-success-500',
  info: 'text-info-500',
  warning: 'text-warning-500',
  error: 'text-error-500',
}

const inputClass = computed(() => {
  const baseClass = 'rounded border-gray-300 focus:ring-0 cursor-pointer'
  return `${baseClass} ${variant[props.color] || variant.default}`
})

const labelClass = computed(() => {
  const baseClass = 'ml-2 text-xs font-semibold cursor-pointer'
  return `${baseClass} ${variant[props.color] || variant.default}`
})
</script>

<template>
  <div class="flex items-center">
    <input v-model="props.modelValue" :id="props.id" :name="props.name" type="checkbox"
           :class="inputClass" @change="emit('update:model-value', ($event.target as HTMLInputElement)?.checked)">
    <label :for="props.id" :class="labelClass">{{ props.label }}</label>
  </div>
</template>

